 23→            const tweenUp = new Konva.Tween({
 24→                node,
 25→                scaleX: 1.8,
 26→                scaleY: 1.8,
 27→                duration: 0.35,
 28→                easing: Konva.Easings.ElasticEaseOut,
 29→                onFinish: () => {
 30→                    // Phase 2: ease back down 1.8 → 1
 31→                    const tweenDown = new Konva.Tween({
 32→                        node,
 33→                        scaleX: 1,
 34→                        scaleY: 1,
 35→                        duration: 0.25,
 36→                        easing: Konva.Easings.EaseOut,
 37→                    });
 38→                    tweenRef.current = tweenDown;
 39→                    tweenDown.play();
 40→                },
 41→            });
 42→            tweenRef.current = tweenUp;
 43→            tweenUp.play();
 44→        } else {
 45→            // Reset to default scale
 46→            node.scaleX(1);
 47→            node.scaleY(1);
 48→        }
 49→
 50→        return () => {
 51→            if (tweenRef.current) {
 52→                tweenRef.current.destroy();
 53→                tweenRef.current = null;
 54→            }
 55→        };
 56→    }, [isPulsing]);
 57→
 58→    return (
 59→        <Group
 60→            ref={groupRef}
 61→            x={x}
 62→            y={y}
 63→        >
 64→            {/* Outer atmosphere — shadow glow */}
 65→            <Circle
 66→                radius={r * 3}
 67→                fill="transparent"
 68→                shadowColor={color}
 69→                shadowBlur={r * 5}
 70→                shadowOpacity={1}
 71→                perfectDrawEnabled={false}
 72→                shadowForStrokeEnabled={false}
 73→                listening={false}
