115→// Step 2: Recompute galaxy edges (similarity between centroids)
116→// ══════════════════════════════════════════════════════════════════════
117→export async function recomputeGalaxyEdges() {
118→    const { data: centroids, error } = await supabase
119→        .from('galaxy_centroids')
120→        .select('user_id, mean_embedding')
121→        .not('mean_embedding', 'is', null);
122→
123→    if (error) throw new Error(`Failed to fetch centroids: ${error.message}`);
124→    if (!centroids || centroids.length < 2) {
125→        console.log('[galaxy-settle] Not enough centroids for edges');
126→        return 0;
127→    }
128→
129→    const THRESHOLD = 0.25;
130→    const edges = [];
131→
132→    for (let i = 0; i < centroids.length; i++) {
133→        for (let j = i + 1; j < centroids.length; j++) {
134→            const a = centroids[i];
135→            const b = centroids[j];
136→
137→            // Parse embeddings (they come as arrays from Supabase)
138→            const embA = Array.isArray(a.mean_embedding) ? a.mean_embedding : null;
139→            const embB = Array.isArray(b.mean_embedding) ? b.mean_embedding : null;
140→            if (!embA || !embB) continue;
141→
142→            const similarity = dot(embA, embB);
143→            if (similarity >= THRESHOLD) {
144→                // Ensure user_a < user_b
145→                const [userA, userB] = a.user_id < b.user_id
146→                    ? [a.user_id, b.user_id]
147→                    : [b.user_id, a.user_id];
148→                edges.push({ user_a: userA, user_b: userB, similarity });
149→            }
150→        }
151→    }
152→
153→    // Clear old edges and insert new ones
154→    await supabase.from('galaxy_edges').delete().neq('similarity', -999);
155→
156→    if (edges.length > 0) {
157→        // Batch insert in chunks of 500
158→        for (let i = 0; i < edges.length; i += 500) {
159→            const chunk = edges.slice(i, i + 500);
160→            const { error: insertErr } = await supabase
161→                .from('galaxy_edges')
162→                .upsert(chunk, { onConflict: 'user_a,user_b' });
163→            if (insertErr) {
164→                console.error('[galaxy-settle] Edge insert error:', insertErr.message);
165→            }
166→        }
167→    }
168→
169→    console.log(`[galaxy-settle] Computed ${edges.length} galaxy edges`);
170→    return edges.length;
171→}
