193→export const computeGalaxySimilarityEdges = (
194→    centroidByUser,
195→    activeUserIds,
196→    threshold = 0.3,
197→    maxEdges = 500
198→) => {
199→    if (!(centroidByUser instanceof Map) || centroidByUser.size < 2) return [];
200→
201→    const users = activeUserIds
202→        ? Array.from(activeUserIds).filter((id) => centroidByUser.has(id))
203→        : Array.from(centroidByUser.keys());
204→
205→    if (users.length < 2) return [];
206→
207→    const minSimilarity = Number.isFinite(Number(threshold)) ? Number(threshold) : 0.3;
208→    const edges = [];
209→
210→    for (let i = 0; i < users.length; i++) {
211→        for (let j = i + 1; j < users.length; j++) {
212→            const userA = users[i];
213→            const userB = users[j];
214→            const sim = cosineSimilarity(centroidByUser.get(userA), centroidByUser.get(userB));
215→            if (sim >= minSimilarity) {
216→                edges.push({ user_a: userA, user_b: userB, similarity: sim });
217→            }
218→        }
219→    }
220→
221→    edges.sort((a, b) => b.similarity - a.similarity);
222→    const limit = normalizeMaxEdges(maxEdges, 500);
223→    return edges.length > limit ? edges.slice(0, limit) : edges;
224→};
225→
226→const clampOffsetMagnitude = (offset, maxOffset) => {
227→    const limit = Math.max(0, Number(maxOffset) || 0);
228→    if (limit === 0) return { dx: 0, dy: 0 };
229→
230→    const mag = Math.sqrt(offset.dx * offset.dx + offset.dy * offset.dy);
231→    if (mag <= limit || mag <= EPSILON) return offset;
232→
233→    return {
234→        dx: (offset.dx / mag) * limit,
235→        dy: (offset.dy / mag) * limit,
236→    };
237→};
