16→export const userHomeCoords = (userId) => {
17→    if (!userId) return { x: 0, y: 0 };
18→    const mid = Math.floor(userId.length / 2);
19→    const xHash = simpleHash(userId.slice(0, mid));
20→    const yHash = simpleHash(userId.slice(mid));
21→    const x = (xHash % 50001) / 50000 * 50000 - 25000;
22→    const y = (yHash % 50001) / 50000 * 50000 - 25000;
23→    return { x, y };
24→};
