174→            ctx.fill();
175→        }
176→
177→        // Bright core — white hot center
178→        const coreGrad = ctx.createRadialGradient(x, y, 0, x, y, r * 0.2);
179→        coreGrad.addColorStop(0, `rgba(255,255,255,${0.95 * opacity})`);
180→        coreGrad.addColorStop(0.4, `rgba(${rgb.r},${rgb.g},${rgb.b},${0.6 * opacity})`);
181→        coreGrad.addColorStop(1, 'rgba(0,0,0,0)');
182→        ctx.beginPath();
183→        ctx.arc(x, y, r * 0.2, 0, TWO_PI);
184→        ctx.fillStyle = coreGrad;
185→        ctx.fill();
186→    };
