 75→        for (const galaxy of galaxies) {
 76→            const seed = simpleHash(galaxy.userId) + 3571;
 77→            const rng = seededRng(seed);
 78→            const color = getStarColor(galaxy.userId);
 79→            const rgb = parseHex(color);
 80→            const galaxyRadius = 250 + (rng() * 100);
 81→
 82→            for (let i = 0; i < DUST_PER_GALAXY; i++) {
 83→                const angle = rng() * TWO_PI;
 84→                const dist = galaxyRadius * (0.15 + rng() * 1.1);
 85→                const localX = Math.cos(angle) * dist;
 86→                const localY = Math.sin(angle) * dist * (0.5 + rng() * 0.4);
 87→
 88→                const twinkleSpeed = 0.0008 + rng() * 0.002;
 89→                const twinklePhase = rng() * TWO_PI;
 90→                const driftSpeed = 0.00003 + rng() * 0.00008;
 91→                const driftAngle = rng() * TWO_PI;
 92→                const driftRadius = 3 + rng() * 12;
 93→                const baseAlpha = 0.08 + rng() * 0.35;
 94→                const size = 0.4 + rng() * 1.6;
 95→
 96→                const warmMix = rng();
 97→                const r = Math.round(rgb.r + (255 - rgb.r) * warmMix * 0.5);
 98→                const g = Math.round(rgb.g + (248 - rgb.g) * warmMix * 0.4);
 99→                const b = Math.round(rgb.b + (220 - rgb.b) * warmMix * 0.3);
100→
101→                allDust.push({
102→                    gx: galaxy.x,
103→                    gy: galaxy.y,
104→                    localX, localY,
105→                    twinkleSpeed, twinklePhase,
106→                    driftSpeed, driftAngle, driftRadius,
107→                    baseAlpha, size,
108→                    r, g, b,
109→                });
110→            }
111→        }
112→
113→        return allDust;
114→    }, [galaxies]);
115→
116→    // Initialize per-cloud rotation offsets when data changes
117→    useEffect(() => {
118→        animRef.current.rotations = nebulaData.map(() => Math.random() * 360);
119→    }, [nebulaData]);
120→
121→    // Animation loop
122→    const animate = useCallback(() => {
123→        const anim = animRef.current;
124→        const now = performance.now();
125→        anim.phase = (now % BREATH_PERIOD) / BREATH_PERIOD;
126→        anim.time = now;
127→
128→        for (let i = 0; i < anim.rotations.length; i++) {
129→            anim.rotations[i] += ROTATION_SPEED;
130→        }
131→
132→        if (shapeRef.current) {
133→            shapeRef.current.getLayer()?.batchDraw();
134→        }
135→
136→        rafRef.current = requestAnimationFrame(animate);
137→    }, []);
138→
139→    useEffect(() => {
140→        rafRef.current = requestAnimationFrame(animate);
141→        return () => {
142→            if (rafRef.current) cancelAnimationFrame(rafRef.current);
143→        };
144→    }, [animate]);
145→
146→    return (
147→        <Layer {...layerProps} listening={false}>
148→            <Shape
149→                ref={shapeRef}
150→                sceneFunc={(ctx) => {
151→                    const anim = animRef.current;
152→                    const scale = 1.0 + 0.15 * Math.sin(anim.phase * TWO_PI);
153→                    const time = anim.time;
154→
155→                    // --- Nebula clouds ---
156→                    for (let i = 0; i < nebulaData.length; i++) {
157→                        const cloud = nebulaData[i];
158→                        const rot = (anim.rotations[i] || 0) * (Math.PI / 180);
159→                        const r = cloud.radius * scale;
160→
161→                        ctx.save();
162→                        ctx.translate(cloud.x, cloud.y);
163→                        ctx.rotate(rot);
164→
165→                        const grad = ctx.createRadialGradient(0, 0, 0, 0, 0, r);
166→                        grad.addColorStop(0, `rgba(${cloud.r},${cloud.g},${cloud.b},0.18)`);
167→                        grad.addColorStop(0.5, `rgba(${cloud.r},${cloud.g},${cloud.b},0.08)`);
168→                        grad.addColorStop(1, 'rgba(0,0,0,0)');
169→
170→                        ctx.beginPath();
171→                        ctx.arc(0, 0, r, 0, TWO_PI);
172→                        ctx.fillStyle = grad;
173→                        ctx.fill();
174→
175→                        ctx.restore();
176→                    }
177→
178→                    // --- Stardust particles ---
179→                    for (let i = 0; i < dustData.length; i++) {
180→                        const d = dustData[i];
181→
182→                        const twinkle = 0.5 + 0.5 * Math.sin(time * d.twinkleSpeed + d.twinklePhase);
183→                        const alpha = d.baseAlpha * twinkle;
184→                        if (alpha < 0.02) continue;
185→
186→                        const driftPhase = time * d.driftSpeed;
187→                        const dx = Math.cos(d.driftAngle + driftPhase) * d.driftRadius;
188→                        const dy = Math.sin(d.driftAngle + driftPhase) * d.driftRadius;
189→
190→                        const px = d.gx + d.localX + dx;
191→                        const py = d.gy + d.localY + dy;
192→                        const sizePulse = d.size * (0.85 + 0.15 * twinkle);
193→
194→                        ctx.beginPath();
195→                        ctx.arc(px, py, sizePulse, 0, TWO_PI);
196→                        ctx.fillStyle = `rgba(${d.r},${d.g},${d.b},${alpha})`;
197→                        ctx.fill();
198→                    }
199→                }}
200→                perfectDrawEnabled={false}
201→                listening={false}
202→            />
203→        </Layer>
204→    );
205→});
