### Phase 1: New File -- `client/src/components/Universe/physics/matterEngine.js`

**Purpose:** Singleton-like factory for the Matter.js engine, world, and configuration. Pure module with zero React dependencies.

```javascript
// matterEngine.js -- Matter.js engine factory and configuration

import Matter from 'matter-js';

const { Engine, World, Bodies, Body, Constraint, Events, Sleeping } = Matter;

// Physics constants
export const PHYSICS_CONFIG = {
    // Engine settings
    enableSleeping: true,
    gravity: { x: 0, y: 0 },           // No global gravity (space!)

    // World damping -- 0.98 per the user's requirement
    // Applied as frictionAir on bodies since Matter.js has no global damping
    globalFrictionAir: 0.02,            // 1 - 0.98 = 0.02

    // Body defaults
    defaultRestitution: 0.4,            // Bounce coefficient
    defaultFriction: 0,                 // No surface friction (space)
    defaultFrictionStatic: 0,

    // Force magnitudes
    anchorSpringK: 0.0015,              // Galaxy anchor spring (soft)
    semanticPullK: 0.0004,              // Cross-galaxy semantic attraction
    pairConstraintStiffness: 0.03,      // Star-to-star constellation bonds
    pairConstraintDamping: 0.1,

    // Collision
    collisionCategory: 0x0001,
    sleepThreshold: 60,                 // Frames of minimal motion before sleep

    // Limits
    maxActiveBodies: 300,
    bodyDestroyDelaySec: 30,
};

/**
 * Create a configured Matter.js engine with zero-gravity space physics.
 */
export function createStarEngine() {
    const engine = Engine.create({
        enableSleeping: PHYSICS_CONFIG.enableSleeping,
        gravity: { ...PHYSICS_CONFIG.gravity },
    });

    // Tune solver for soft-body constellation feel
    engine.constraintIterations = 2;
    engine.positionIterations = 4;
    engine.velocityIterations = 2;

    return engine;
}

/**
 * Create a star body at the given world position.
 */
export function createStarBody(postId, x, y, radius, mass) {
    const body = Bodies.circle(x, y, radius * 1.5, {  // slightly larger than visual
        label: postId,
        mass: mass,
        restitution: PHYSICS_CONFIG.defaultRestitution,
        friction: PHYSICS_CONFIG.defaultFriction,
        frictionStatic: PHYSICS_CONFIG.defaultFrictionStatic,
        frictionAir: PHYSICS_CONFIG.globalFrictionAir,
        collisionFilter: { category: PHYSICS_CONFIG.collisionCategory },
        sleepThreshold: PHYSICS_CONFIG.sleepThreshold,
        isSleeping: false,
    });

    return body;
}

/**
 * Create a soft constraint between two star bodies (constellation bond).
 */
export function createConstellationConstraint(bodyA, bodyB, similarity) {
    const distance = 40 + (1 - similarity) * 120;  // closer for higher similarity

    return Constraint.create({
        bodyA,
        bodyB,
        length: distance,
        stiffness: PHYSICS_CONFIG.pairConstraintStiffness * similarity,
        damping: PHYSICS_CONFIG.pairConstraintDamping,
        render: { visible: false },
    });
}

/**
 * Compute mass from like_count, matching getStarRadius() scaling.
 */
export function getStarMass(likeCount) {
    const likes = Math.min(likeCount || 0, 20);
    const radius = 6 + likes * 0.3;
    return Math.PI * radius * radius * 0.01;
}

export { Engine, World, Bodies, Body, Constraint, Events, Sleeping };
```

