### Phase 2: New File -- `client/src/components/Universe/physics/semanticForces.js`

**Purpose:** Pure functions that compute force vectors from server similarity data. No React, no Matter dependency. These functions are called each physics frame.

```javascript
// semanticForces.js -- Compute force vectors from server-provided similarity data

/**
 * Build lookup maps from server data for O(1) per-star force computation.
 * Called once when starPulls/similarPairs change (not every frame).
 */
export function buildSemanticMaps(starPulls, similarPairs) {
    // starPullMap: postId -> [{galaxyUserId, similarity}]
    const starPullMap = new Map();
    if (Array.isArray(starPulls)) {
        for (const pull of starPulls) {
            if (!pull?.post_id || !pull?.galaxy_user_id) continue;
            if (!starPullMap.has(pull.post_id)) {
                starPullMap.set(pull.post_id, []);
            }
            starPullMap.get(pull.post_id).push({
                galaxyUserId: pull.galaxy_user_id,
                similarity: Number(pull.similarity) || 0,
            });
        }
    }

    // pairMap: postId -> [{otherPostId, similarity}]
    const pairMap = new Map();
    if (Array.isArray(similarPairs)) {
        for (const pair of similarPairs) {
            if (!pair?.post_a || !pair?.post_b) continue;
            const sim = Number(pair.similarity) || 0;

            if (!pairMap.has(pair.post_a)) pairMap.set(pair.post_a, []);
            pairMap.get(pair.post_a).push({ otherPostId: pair.post_b, similarity: sim });

            if (!pairMap.has(pair.post_b)) pairMap.set(pair.post_b, []);
            pairMap.get(pair.post_b).push({ otherPostId: pair.post_a, similarity: sim });
        }
    }

    return { starPullMap, pairMap };
}

/**
 * Compute the galaxy-anchor force for a star.
 * Pulls the star softly toward its galaxy's animated position + local offset.
 */
export function computeAnchorForce(bodyPos, anchorPos, springK) {
    const dx = anchorPos.x - bodyPos.x;
    const dy = anchorPos.y - bodyPos.y;
    return { fx: dx * springK, fy: dy * springK };
}

/**
 * Compute cross-galaxy semantic pull forces for a star.
 * Uses the starPullMap built from server's get_star_galaxy_pulls RPC.
 */
export function computeSemanticPullForce(
    bodyPos, postId, starPullMap, galaxyPositions, pullK
) {
    let fx = 0, fy = 0;
    const pulls = starPullMap.get(postId);
    if (!pulls) return { fx, fy };

    for (const { galaxyUserId, similarity } of pulls) {
        const galaxyPos = galaxyPositions.get(galaxyUserId);
        if (!galaxyPos) continue;

        const dx = galaxyPos.x - bodyPos.x;
        const dy = galaxyPos.y - bodyPos.y;
        const dist = Math.sqrt(dx * dx + dy * dy) || 1;

        // Force proportional to similarity, inversely proportional to distance (capped)
        const strength = similarity * pullK;
        const cappedDist = Math.max(dist, 50);  // prevent extreme forces at close range

        fx += (dx / cappedDist) * strength;
        fy += (dy / cappedDist) * strength;
    }

    return { fx, fy };
}
```

