422→
423→            payload.push({
424→                post_id: post.id,
425→                settled_x: Math.round(pos.x * 100) / 100,
426→                settled_y: Math.round(pos.y * 100) / 100,
427→            });
428→        }
429→
430→        payload.sort((a, b) => String(a.post_id).localeCompare(String(b.post_id)));
431→        return payload;
432→    }, [activePosts, getComputedStarPosition, isSettled]);
433→
434→    // Placeholder persistence hook: debounced Supabase RPC for settled positions.
435→    useEffect(() => {
436→        if (!ENABLE_SETTLED_RPC_SAVE) return;
